// Regenerates src/curriculum-data/quizBank.ts from every JSON file in
// content-source/quiz-bank/. Run this after adding/editing quiz files:
//
//   node scripts/build-quiz-bank.mjs
//
// This keeps the actual app bundle clean (one generated file, no folder
// scanning at runtime) while letting you just drop JSON files in as you
// get them, in any order, one grade/subject at a time.

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");
const quizDir = path.join(root, "content-source", "quiz-bank");
const outFile = path.join(root, "src", "curriculum-data", "quizBank.ts");

function slugify(name) {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}

const files = fs.readdirSync(quizDir).filter(
  (f) => f.endsWith(".json") && !f.startsWith("_")
);

const bank = {}; // key: "9-mathematics" or "11-mathematics-natural" -> questions[]
let totalQuestions = 0;
const errors = [];

for (const file of files) {
  const match = file.match(/^g(\d+)-([a-z0-9-]+)\.json$/i);
  if (!match) {
    errors.push(`Skipped ${file}: filename doesn't match g{grade}-{subject-slug}.json`);
    continue;
  }
  const [, grade, subjectSlug] = match;
  const fullPath = path.join(quizDir, file);
  let questions;
  try {
    questions = JSON.parse(fs.readFileSync(fullPath, "utf-8"));
  } catch (e) {
    errors.push(`Skipped ${file}: invalid JSON (${e.message})`);
    continue;
  }
  if (!Array.isArray(questions)) {
    errors.push(`Skipped ${file}: must be a JSON array of questions`);
    continue;
  }
  // Basic shape validation, so a malformed file doesn't ship a broken quiz
  const badQuestions = questions.filter(
    (q) =>
      typeof q.id !== "string" ||
      typeof q.question !== "string" ||
      !Array.isArray(q.options) ||
      q.options.length < 2 ||
      typeof q.answerIndex !== "number" ||
      q.answerIndex < 0 ||
      q.answerIndex >= q.options.length ||
      typeof q.explanation !== "string"
  );
  if (badQuestions.length > 0) {
    errors.push(
      `${file}: ${badQuestions.length} question(s) have missing/invalid fields (check id/question/options/answerIndex/explanation) — file skipped entirely until fixed`
    );
    continue;
  }

  const key = `${grade}-${subjectSlug}`;
  bank[key] = questions;
  totalQuestions += questions.length;
}

const header = `// AUTO-GENERATED by scripts/build-quiz-bank.mjs — do not edit by hand.
// Source files: content-source/quiz-bank/*.json
// To add or update quizzes, edit the JSON files there and re-run:
//   node scripts/build-quiz-bank.mjs
`;

const body = `${header}
import { QuizQuestion } from "../types";

export const QUIZ_BANK: Record<string, QuizQuestion[]> = ${JSON.stringify(bank, null, 2)};

function slugify(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}

// Same signature as before — callers (PracticeQuiz.tsx) don't need to change.
// Tries an exact "{grade}-{subjectSlug}" match first, then falls back to
// a stream-suffixed key if the plain one isn't found (e.g. "-natural"/"-social").
export function getQuizForSubject(
  grade: string,
  subjectName: string,
  unitTitle: string,
  stream?: string
): QuizQuestion[] | null {
  const subjectSlug = slugify(subjectName);
  const plainKey = \`\${grade}-\${subjectSlug}\`;
  const streamKey = stream ? \`\${grade}-\${subjectSlug}-\${slugify(stream)}\` : null;

  const questions = (streamKey && QUIZ_BANK[streamKey]) || QUIZ_BANK[plainKey];
  if (!questions || questions.length === 0) return null;

  const shuffled = [...questions].sort(() => 0.5 - Math.random());
  return shuffled;
}
`;

fs.writeFileSync(outFile, body, "utf-8");

console.log(`Wrote ${outFile}`);
console.log(`Grade/subject combos: ${Object.keys(bank).length}`);
console.log(`Total questions: ${totalQuestions}`);
if (errors.length > 0) {
  console.log("\nWarnings (these files were skipped, fix and re-run):");
  errors.forEach((e) => console.log(" - " + e));
}
